private struct AudibleTabHost<Content: View>: View {
    let title: String
    let icon: String
    @ViewBuilder var content: () -> Content
    var body: some View { content() }
}

private enum AudibleScreenFactory {
    @ViewBuilder
    static func screen(for tab: String) -> some View {
        switch tab.lowercased() {
        case let t where t.contains("accueil") || t.contains("home") || t.contains("radio") || t.contains("new") || t.contains("sample"):
            AudibleHomeScreen()
        case let t where t.contains("search") || t.contains("recherch") || t.contains("discover"):
            AudibleSearchScreen()
        case let t where t.contains("library") || t.contains("biblioth") || t.contains("premium") || t.contains("profil"):
            AudibleLibraryScreen()
        default:
            AudibleGenericListScreen(title: tab)
        }
    }
}
