private struct AudibleHomeScreen: View {
    var body: some View {
        ZStack(alignment: .bottom) {
            ScrollView {
                VStack(alignment: .leading, spacing: 20) {
                    Text("Bonsoir").font(.system(size: 28, weight: .bold)).foregroundStyle(AudibleTokens.audTextPrimary).padding(.horizontal)
                    LazyVGrid(columns: [GridItem(.flexible()), GridItem(.flexible())], spacing: 12) {
                        ForEach(AudibleDemoData.recent) { item in
                            AudibleRecentTile(item: item, surface: AudibleTokens.audSurface1)
                        }
                    }
                    .padding(.horizontal)
                    Text("Récemment joué").font(.system(size: 22, weight: .bold)).foregroundStyle(AudibleTokens.audTextPrimary).padding(.horizontal)
                    ScrollView(.horizontal, showsIndicators: false) {
                        HStack(spacing: 12) {
                            ForEach(AudibleDemoData.playlists) { pl in
                                VStack(alignment: .leading) {
                                    RoundedRectangle(cornerRadius: 6).fill(pl.color).frame(width: 140, height: 140)
                                    Text(pl.title).font(.system(size: 14, weight: .semibold)).foregroundStyle(AudibleTokens.audTextPrimary).lineLimit(1)
                                }
                            }
                        }
                        .padding(.horizontal)
                    }
                }
                .padding(.vertical).padding(.bottom, 80)
            }
            .background(AudibleTokens.audCanvas.ignoresSafeArea())
            AudibleMiniPlayer(accent: AudibleTokens.audTextPrimary, surface: AudibleTokens.audSurface1, textPri: AudibleTokens.audTextPrimary)
        }
    }
}

private struct AudibleRecentTile: View {
